class Solution {
public:
    int calculate(string s) {
        int res = 0, num = 0, sign = 1;
        stack<int> st;
        for (int i = 0; i < s.size(); i++) {
            if (s[i] >= '0' && s[i] <= '9') {
                num = num * 10 + (s[i] - '0');
            }
            if (s[i] == '+' || s[i] == '-' || s[i] == '*' || s[i] == '/' || s[i] == ' ') {
                res += sign * num;
                num = 0;
                if (s[i] == '+') sign = 1;
                else if (s[i] == '-') sign = -1;
                else if (s[i] == '*' || s[i] == '/') {
                    st.push(sign);
                    sign = 1;
                }
            }
            if (s[i] == '*' || s[i] == '/') {
                int op = st.top(); st.pop();
                if (s[i] == '*') res += op * num;
                else res -= op * num;
            }
        }
        res += sign * num;
        return res;
    }
};
```

